import React, { useState } from 'react';

const COLORS = ['#2563eb','#7c3aed','#db2777','#059669','#d97706','#dc2626'];

function scoreColor(score) {
  if (score >= 70) return { color: '#16a34a', bg: '#f0fdf4', border: '#bbf7d0' };
  if (score >= 40) return { color: '#d97706', bg: '#fffbeb', border: '#fde68a' };
  return { color: '#dc2626', bg: '#fef2f2', border: '#fecaca' };
}

const rankLabel = (rank) => {
  if (rank === 1) return { label: '🥇 Top Match', bg: '#fff7ed', color: '#c2410c', border: '#fed7aa' };
  if (rank === 2) return { label: '🥈 #2 Ranked', bg: '#f0fdf4', color: '#166534', border: '#bbf7d0' };
  if (rank === 3) return { label: '🥉 #3 Ranked', bg: '#eff6ff', color: '#1e40af', border: '#bfdbfe' };
  return { label: `#${rank}`, bg: '#f9fafb', color: '#4b5563', border: '#e5e7eb' };
};

const s = {
  card: {
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 10,
    overflow: 'hidden',
    marginBottom: 16,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
    transition: 'box-shadow 0.2s',
  },
  cardTop: {
    padding: '16px 20px',
    display: 'flex',
    alignItems: 'center',
    gap: 14,
    borderBottom: '1px solid #f3f4f6',
  },
  avatar: (color) => ({
    width: 44, height: 44,
    borderRadius: 8,
    background: color,
    color: '#fff',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontWeight: 700,
    fontSize: 15,
    flexShrink: 0,
  }),
  name: { fontWeight: 600, fontSize: 15, color: '#111827', marginBottom: 1 },
  role: { fontSize: 12, color: '#6b7280' },
  rankBadge: (r) => ({
    marginLeft: 'auto',
    padding: '4px 10px',
    borderRadius: 20,
    fontSize: 11,
    fontWeight: 600,
    background: r.bg,
    color: r.color,
    border: `1px solid ${r.border}`,
  }),
  cardBody: { padding: '16px 20px' },
  scoreRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 },
  scoreLabel: { fontSize: 12, color: '#6b7280', fontWeight: 500 },
  scoreVal: (sc) => ({
    fontWeight: 700,
    fontSize: 20,
    color: scoreColor(sc).color,
  }),
  bar: { height: 6, background: '#f3f4f6', borderRadius: 3, overflow: 'hidden', marginBottom: 14 },
  barFill: (sc) => ({
    height: '100%',
    width: `${sc}%`,
    borderRadius: 3,
    background: scoreColor(sc).color,
    transition: 'width 0.8s ease',
  }),
  grid2: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 12 },
  skillGroup: {},
  groupLabel: { fontSize: 11, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 5, fontWeight: 500 },
  pillRow: { display: 'flex', flexWrap: 'wrap', gap: 4 },
  pill: (type) => {
    const map = {
      match: { bg: '#f0fdf4', color: '#166534', border: '#bbf7d0' },
      missing: { bg: '#fef2f2', color: '#991b1b', border: '#fecaca' },
      bonus: { bg: '#eff6ff', color: '#1e40af', border: '#bfdbfe' },
    };
    const c = map[type] || map.bonus;
    return {
      padding: '3px 8px',
      borderRadius: 4,
      fontSize: 11,
      fontWeight: 500,
      background: c.bg,
      color: c.color,
      border: `1px solid ${c.border}`,
      ...(type === 'missing' ? { textDecoration: 'line-through', opacity: 0.7 } : {}),
    };
  },
  footer: {
    padding: '12px 20px',
    background: '#f9fafb',
    borderTop: '1px solid #f3f4f6',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  },
  meta: { fontSize: 12, color: '#6b7280', display: 'flex', gap: 16 },
  actions: { display: 'flex', gap: 8 },
  btn: (primary) => ({
    padding: '6px 14px',
    borderRadius: 6,
    fontSize: 12,
    fontWeight: 500,
    border: `1px solid ${primary ? '#2563eb' : '#d1d5db'}`,
    background: primary ? '#2563eb' : '#fff',
    color: primary ? '#fff' : '#374151',
    cursor: 'pointer',
    transition: 'all 0.15s',
  }),
  expandBtn: {
    width: '100%',
    padding: '8px',
    background: 'none',
    border: 'none',
    borderTop: '1px solid #f3f4f6',
    fontSize: 12,
    color: '#2563eb',
    cursor: 'pointer',
    fontWeight: 500,
  },
  expandBody: {
    padding: '16px 20px',
    borderTop: '1px solid #f3f4f6',
    background: '#fafafa',
  },
  detailGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 },
  detailItem: { background: '#fff', border: '1px solid #e5e7eb', borderRadius: 6, padding: '10px 12px' },
  detailKey: { fontSize: 11, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 3 },
  detailVal: { fontSize: 13, color: '#111827', fontWeight: 500 },
};

export default function CandidateCard({ candidate, index, onShortlist }) {
  const [expanded, setExpanded] = useState(false);
  const [shortlisted, setShortlisted] = useState(false);
  const c = candidate;
  const color = COLORS[index % COLORS.length];
  const initials = c.name ? c.name.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() : '??';
  const rank = rankLabel(c.rank);
  const sc = scoreColor(c.final_score);

  const handleShortlist = () => {
    setShortlisted(true);
    onShortlist && onShortlist(c);
  };

  return (
    <div style={s.card}>
      {/* Top */}
      <div style={s.cardTop}>
        <div style={s.avatar(color)}>{initials}</div>
        <div>
          <div style={s.name}>{c.name || 'Unknown Candidate'}</div>
          <div style={s.role}>{c.email || 'No email found'}</div>
        </div>
        <div style={s.rankBadge(rank)}>{rank.label}</div>
      </div>

      {/* Body */}
      <div style={s.cardBody}>
        {/* Score */}
        <div style={s.scoreRow}>
          <span style={s.scoreLabel}>Overall Match Score</span>
          <span style={s.scoreVal(c.final_score)}>{c.final_score}%</span>
        </div>
        <div style={s.bar}><div style={s.barFill(c.final_score)} /></div>

        {/* Sub-scores */}
        <div style={{ display: 'flex', gap: 12, marginBottom: 14 }}>
          {[
            { label: 'Skill Match', val: c.skill_score + '%' },
            { label: 'Semantic', val: c.semantic_score + '%' },
            { label: 'Experience', val: c.experience || '—' },
          ].map(item => (
            <div key={item.label} style={{ flex: 1, background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: 6, padding: '8px 10px' }}>
              <div style={{ fontSize: 10, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 2 }}>{item.label}</div>
              <div style={{ fontSize: 14, fontWeight: 600, color: '#111827' }}>{item.val}</div>
            </div>
          ))}
        </div>

        {/* Skills */}
        <div style={s.grid2}>
          <div style={s.skillGroup}>
            <div style={s.groupLabel}>✓ Matched ({c.matched_skills?.length || 0})</div>
            <div style={s.pillRow}>
              {c.matched_skills?.length > 0
                ? c.matched_skills.map(sk => <span key={sk} style={s.pill('match')}>{sk}</span>)
                : <span style={{ fontSize: 12, color: '#9ca3af' }}>None</span>}
            </div>
          </div>
          <div style={s.skillGroup}>
            <div style={s.groupLabel}>✗ Missing ({c.missing_skills?.length || 0})</div>
            <div style={s.pillRow}>
              {c.missing_skills?.length > 0
                ? c.missing_skills.map(sk => <span key={sk} style={s.pill('missing')}>{sk}</span>)
                : <span style={{ fontSize: 12, color: '#16a34a', fontWeight: 500 }}>All matched!</span>}
            </div>
          </div>
        </div>

        {c.bonus_skills?.length > 0 && (
          <div style={{ marginTop: 8 }}>
            <div style={s.groupLabel}>+ Bonus Skills</div>
            <div style={s.pillRow}>
              {c.bonus_skills.map(sk => <span key={sk} style={s.pill('bonus')}>{sk}</span>)}
            </div>
          </div>
        )}
      </div>

      {/* Expand toggle */}
      <button style={s.expandBtn} onClick={() => setExpanded(!expanded)}>
        {expanded ? '▲ Hide Details' : '▼ Show Full Profile'}
      </button>

      {/* Expanded */}
      {expanded && (
        <div style={s.expandBody}>
          <div style={s.detailGrid}>
            <div style={s.detailItem}>
              <div style={s.detailKey}>Education</div>
              <div style={s.detailVal}>{Array.isArray(c.education) ? c.education[0] : c.education || '—'}</div>
            </div>
            <div style={s.detailItem}>
              <div style={s.detailKey}>Experience</div>
              <div style={s.detailVal}>{c.experience || '—'}</div>
            </div>
            <div style={s.detailItem}>
              <div style={s.detailKey}>Phone</div>
              <div style={s.detailVal}>{c.phone || '—'}</div>
            </div>
            <div style={s.detailItem}>
              <div style={s.detailKey}>File</div>
              <div style={s.detailVal}>{c.filename || '—'}</div>
            </div>
          </div>
          {c.education?.length > 1 && (
            <div style={{ marginTop: 10 }}>
              <div style={{ ...s.groupLabel, marginBottom: 4 }}>All Education</div>
              {c.education.map((e, i) => (
                <div key={i} style={{ fontSize: 12, color: '#374151', marginBottom: 2 }}>• {e}</div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Footer */}
      <div style={s.footer}>
        <div style={s.meta}>
          <span>🎓 {Array.isArray(c.education) ? c.education[0]?.slice(0, 30) + '...' : c.education || '—'}</span>
          <span>📁 {c.filename || '—'}</span>
        </div>
        <div style={s.actions}>
          <button style={s.btn(false)} onClick={() => setExpanded(!expanded)}>
            {expanded ? 'Collapse' : 'Details'}
          </button>
          <button
            style={{ ...s.btn(true), background: shortlisted ? '#16a34a' : '#2563eb', borderColor: shortlisted ? '#16a34a' : '#2563eb' }}
            onClick={handleShortlist}
          >
            {shortlisted ? '✓ Shortlisted' : 'Shortlist →'}
          </button>
        </div>
      </div>
    </div>
  );
}
